      ]),
      suite("S", "r3.xml", [
        ["alpha", "passed", 0.1],
        ["bravo", "failed", 0.1],
      ]),
    ];
    const flaky = aggregate(suites).flaky;
    expect(flaky.map((f) => f.name)).toEqual(["bravo", "alpha"]);
  });
});

